#include <unordered_set>
#include <vector>
#include <string>

class Solution {
public:
    std::vector<std::string> uncommonFromSentences(std::string s1, std::string s2) {
        std::unordered_set<std::string> wordSet1;
        std::unordered_set<std::string> wordSet2;

        // Add words to word sets
        for (const auto& word : s1) {
            wordSet1.insert(word);
        }
        for (const auto& word : s2) {
            wordSet2.insert(word);
        }

        // Find uncommon words
        std::vector<std::string> uncommonWords;
        for (const auto& word : s1) {
            if (!wordSet2.count(word)) {
                uncommonWords.push_back(word);
            }
        }
        for (const auto& word : s2) {
            if (!wordSet1.count(word)) {
                uncommonWords.push_back(word);
            }
        }

        return uncommonWords;
    }
};
